<template>
    <div>
      <meta http-equiv="Content-Security-Policy" content="upgrade-insecure-requests" />
        <input v-model="phone">
        <input type="button" value="发送" @click="mes">
        <b>{{lo}}</b>
    </div>
</template>

<script>
export default {
  name: 'Message',
  data:function(){
    return{
      phone:"",
      lo:""
    }
  },
  methods:{
    mes:function(){
      if(this.phone==""){
        alert("不能为空");
        return;
      }
      var _this=this;
      this.$http.get("http://kafka.free.idcfengye.com/mobile/"+this.phone).then(function(res){
          console.info(res);
          _this.lo=res.data;
      });


    }
  }
}
</script>
